const AVATAR_COLORS = ["#1a8fe3", "#10c48a", "#e53935", "#f59e0b", "#7c3aed", "#db2777"];

function Avatar({ initials, size = 44, idx = 0 }) {
  const color = AVATAR_COLORS[idx % AVATAR_COLORS.length];
  return (
    <div style={{
      width: size, height: size, borderRadius: "50%", background: color,
      display: "flex", alignItems: "center", justifyContent: "center",
      color: "#fff", fontWeight: 700, fontSize: size * 0.32, flexShrink: 0
    }}>{initials}</div>
  );
}

function Badge({ text, color = "#1a8fe3", bg = "#e8f4fd" }) {
  return (
    <span style={{ background: bg, color, borderRadius: 20, padding: "2px 10px", fontSize: 11, fontWeight: 600 }}>{text}</span>
  );
}

function SeverityBadge({ level }) {
  const map = {
    low: { bg: "#dcfce7", color: "#15803d", dot: "#22c55e", label: "🟢 Low" },
    medium: { bg: "#fef9c3", color: "#92400e", dot: "#eab308", label: "🟡 Medium" },
    high: { bg: "#fee2e2", color: "#991b1b", dot: "#ef4444", label: "🔴 High" },
  };
  const s = map[level] || map.low;
  return (
    <span style={{ background: s.bg, color: s.color, borderRadius: 20, padding: "3px 12px", fontSize: 12, fontWeight: 600 }}>{s.label}</span>
  );
}

function Card({ children, style = {}, onClick }) {
  return (
    <div onClick={onClick} style={{
      background: "#fff", borderRadius: 14, border: `1px solid ${COLORS.border}`,
      padding: "1.2rem", boxShadow: "0 2px 12px rgba(26,143,227,0.07)",
      transition: "box-shadow 0.2s", cursor: onClick ? "pointer" : "default",
      ...style
    }}
      onMouseEnter={e => { if (onClick) e.currentTarget.style.boxShadow = "0 6px 24px rgba(26,143,227,0.15)"; }}
      onMouseLeave={e => { if (onClick) e.currentTarget.style.boxShadow = "0 2px 12px rgba(26,143,227,0.07)"; }}
    >{children}</div>
  );
}

function Btn({ children, onClick, variant = "primary", style = {}, small = false }) {
  const base = {
    border: "none", borderRadius: 8, cursor: "pointer", fontWeight: 600,
    fontSize: small ? 12 : 14, padding: small ? "6px 14px" : "10px 22px",
    transition: "all 0.18s", ...style
  };
  const variants = {
    primary: { background: COLORS.primary, color: "#fff" },
    secondary: { background: COLORS.secondary, color: "#fff" },
    outline: { background: "transparent", color: COLORS.primary, border: `1px solid ${COLORS.primary}` },
    danger: { background: COLORS.danger, color: "#fff" },
    ghost: { background: "#f0f7ff", color: COLORS.primary, border: `1px solid ${COLORS.border}` },
  };
  return (
    <button style={{ ...base, ...variants[variant] }} onClick={onClick}
      onMouseEnter={e => { e.currentTarget.style.opacity = "0.88"; e.currentTarget.style.transform = "translateY(-1px)"; }}
      onMouseLeave={e => { e.currentTarget.style.opacity = "1"; e.currentTarget.style.transform = "none"; }}
    >{children}</button>
  );
}

function Input({ label, type = "text", value, onChange, placeholder, options, required }) {
  return (
    <div style={{ marginBottom: 14 }}>
      {label && <label style={{ fontSize: 13, fontWeight: 600, color: COLORS.textPrimary, display: "block", marginBottom: 4 }}>{label}{required && <span style={{ color: COLORS.danger }}> *</span>}</label>}
      {options ? (
        <select value={value} onChange={onChange} style={{ width: "100%", padding: "9px 12px", borderRadius: 8, border: `1px solid ${COLORS.border}`, fontSize: 14, outline: "none", background: "#fff", color: COLORS.textPrimary }}>
          <option value="">Select…</option>
          {options.map(o => <option key={o} value={o}>{o}</option>)}
        </select>
      ) : (
        <input type={type} value={value} onChange={onChange} placeholder={placeholder} style={{
          width: "100%", padding: "9px 12px", borderRadius: 8, border: `1px solid ${COLORS.border}`,
          fontSize: 14, outline: "none", background: "#fff", color: COLORS.textPrimary, boxSizing: "border-box"
        }} />
      )}
    </div>
  );
}
// ─── ADMIN LOGIN PAGE ─────────────────────────────────────────────────────────
function AdminLoginPage({ onNav, onLogin, authError, onClearError }) {
  const [email, setEmail]       = useState("");
  const [password, setPassword] = useState("");
  const [error, setError]       = useState("");
  const [loading, setLoading]   = useState(false);
  const [showPass, setShowPass] = useState(false);

  const handleSubmit = async () => {
    if (!email || !password) { setError("Please enter email and password."); return; }
    setLoading(true); setError("");
    try {
      await onLogin("admin", { email, name: "Admin", _isSignup: false }, password);
    } catch { setError("Invalid admin credentials."); }
    setLoading(false);
  };

  return (
    <div style={{ minHeight:"100vh", background:COLORS.bg, display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"'Segoe UI',system-ui,sans-serif" }}>
      <style>{`
        .admin-inp { width:100%; padding:11px 14px; background:#fff; border:1.5px solid ${COLORS.border}; border-radius:10px; color:${COLORS.textPrimary}; font-size:14px; outline:none; box-sizing:border-box; transition:border-color 0.2s,box-shadow 0.2s; font-family:inherit; }
        .admin-inp:focus { border-color:${COLORS.primary}; box-shadow:0 0 0 3px rgba(26,143,227,0.1); }
        .admin-inp::placeholder { color:#94a3b8; }
        .admin-login-btn { width:100%; padding:13px; background:linear-gradient(135deg,${COLORS.primary},${COLORS.primaryDark}); border:none; border-radius:10px; color:#fff; font-size:14px; font-weight:700; cursor:pointer; transition:all 0.2s; letter-spacing:0.3px; font-family:inherit; }
        .admin-login-btn:hover { transform:translateY(-1px); box-shadow:0 6px 20px rgba(26,143,227,0.35); }
        .admin-login-btn:disabled { opacity:0.65; cursor:not-allowed; transform:none; box-shadow:none; }
      `}</style>

      <div style={{ width:"100%", maxWidth:420, padding:"0 20px" }}>

        {/* Logo area */}
        <div style={{ textAlign:"center", marginBottom:28 }}>
          <div style={{ width:56, height:56, background:`linear-gradient(135deg,${COLORS.primary},${COLORS.primaryDark})`, borderRadius:16, display:"flex", alignItems:"center", justifyContent:"center", margin:"0 auto 14px", boxShadow:`0 6px 20px rgba(26,143,227,0.25)` }}>
            <img src={CAMPUS_TRIAGE_LOGO} alt="CampusTriage" style={{ height:38, objectFit:"contain" }} />
          </div>
          <div style={{ fontSize:22, fontWeight:800, color:COLORS.textPrimary, letterSpacing:"-0.4px" }}>Admin Console</div>
          <div style={{ fontSize:13, color:COLORS.textSecondary, marginTop:5 }}>CampusTriage · Super Administrator</div>
        </div>

        {/* Card */}
        <div style={{ background:"#fff", border:`1px solid ${COLORS.border}`, borderRadius:16, padding:"28px 28px 24px", boxShadow:"0 4px 24px rgba(26,143,227,0.08)" }}>

          {/* Security notice */}
          <div style={{ background:"#f0f7ff", border:`1px solid rgba(26,143,227,0.2)`, borderRadius:9, padding:"10px 14px", marginBottom:20, display:"flex", alignItems:"center", gap:8 }}>
            <span style={{ fontSize:14 }}>🔒</span>
            <span style={{ fontSize:12, color:COLORS.primary, fontWeight:500 }}>Restricted access — Admin credentials required</span>
          </div>

          {(error || authError) && (
            <div style={{ background:"#fee2e2", border:"1px solid #fecaca", borderRadius:9, padding:"10px 14px", fontSize:13, color:"#991b1b", marginBottom:18 }}>
              ⚠️ {error || authError}
            </div>
          )}

          <div style={{ marginBottom:16 }}>
            <label style={{ fontSize:12, fontWeight:600, color:COLORS.textSecondary, display:"block", marginBottom:7, letterSpacing:"0.3px" }}>Admin Email</label>
            <input className="admin-inp" type="email" value={email}
              placeholder="admin@campustriage.com"
              onChange={e => { setEmail(e.target.value); setError(""); onClearError?.(); }} />
          </div>

          <div style={{ marginBottom:22 }}>
            <label style={{ fontSize:12, fontWeight:600, color:COLORS.textSecondary, display:"block", marginBottom:7, letterSpacing:"0.3px" }}>Password</label>
            <div style={{ position:"relative" }}>
              <input className="admin-inp" type={showPass ? "text" : "password"} value={password}
                placeholder="••••••••"
                onChange={e => { setPassword(e.target.value); setError(""); }}
                onKeyDown={e => e.key === "Enter" && handleSubmit()} />
              <button onClick={() => setShowPass(p => !p)} style={{ position:"absolute", right:12, top:"50%", transform:"translateY(-50%)", background:"none", border:"none", color:COLORS.textSecondary, cursor:"pointer", fontSize:12, fontWeight:600, fontFamily:"inherit" }}>
                {showPass ? "Hide" : "Show"}
              </button>
            </div>
          </div>

          <button className="admin-login-btn" onClick={handleSubmit} disabled={loading}>
            {loading ? "⏳ Authenticating…" : "🔐 Access Admin Console"}
          </button>

          <div style={{ textAlign:"center", marginTop:18 }}>
            <span onClick={() => onNav("landing")} style={{ fontSize:12, color:COLORS.textSecondary, cursor:"pointer" }}>
              ← Back to CampusTriage
            </span>
          </div>
        </div>

        <div style={{ textAlign:"center", marginTop:16, fontSize:11, color:"#94a3b8" }}>
          Restricted access · All actions are logged
        </div>
      </div>
    </div>
  );
}

