// ─── PAGE: STUDENT AUTH ──────────────────────────────────────────────────────
// Derive a human-readable college name from a college email domain
function deriveCollegeFromEmail(email) {
  const domain = (email.split("@")[1] || "").toLowerCase();
  const knownDomains = {
    "bits-hyderabad.ac.in": "BITS Pilani, Hyderabad",
    "pilani.bits-pilani.ac.in": "BITS Pilani",
    "goa.bits-pilani.ac.in": "BITS Pilani, Goa",
    "hyderabad.bits-pilani.ac.in": "BITS Pilani, Hyderabad",
    "vitap.ac.in": "VIT-AP University",
    "vit.ac.in": "VIT Vellore",
    "nitw.ac.in": "NIT Warangal",
    "iith.ac.in": "IIT Hyderabad",
    "iitb.ac.in": "IIT Bombay",
    "iitd.ac.in": "IIT Delhi",
    "iitm.ac.in": "IIT Madras",
    "iisc.ac.in": "IISc Bangalore",
    "nits.ac.in": "NIT Silchar",
  };
  if (knownDomains[domain]) return knownDomains[domain];
  // Generic: capitalise domain parts
  const parts = domain.replace(/\.(edu|ac\.in|edu\.in)$/, "").split(".");
  return parts.map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(" ");
}

function AuthPage({ mode, onNav, onLogin, authError, onClearError }) {
  const [form, setForm] = useState({
    name: "", email: "", password: "", confirm: "", college: "",
  });
  const [localError, setLocalError] = useState("");
  const [loading, setLoading] = useState(false);
  const isLogin = mode === "studentLogin";
  const isDoc = mode === "doctorLogin" || mode === "doctorSignup";
  const isDocSignup = mode === "doctorSignup";

  // Merge local validation error + Firebase error from parent
  const error = localError || authError || "";

  const [docForm, setDocForm] = useState({
    name: "", email: "", password: "", phone: "", gender: "", qualification: "",
    experience: "", hospital: "", specialization: "", fee: "300", timings: "", licenseId: ""
  });

  const handle = async () => {
    setLocalError("");
    if (onClearError) onClearError();

    if (isDocSignup) {
      if (!docForm.name || !docForm.email || !docForm.password) { setLocalError("Please fill all required fields."); return; }
      setLoading(true);
      await onLogin("doctor", { ...docForm, _isSignup: true }, docForm.password);
      setLoading(false);
      return;
    }
    if (isDoc) {
      if (!form.email || !form.password) { setLocalError("Please enter your email and password."); return; }
      const nameFromEmail = form.email.split("@")[0].replace(/[._]/g, " ").replace(/\b\w/g, c => c.toUpperCase());
      setLoading(true);
      await onLogin("doctor", { name: nameFromEmail, email: form.email, _isSignup: false }, form.password);
      setLoading(false);
      return;
    }
    if (isLogin) {
      if (!form.email || !form.password) { setLocalError("Please enter your email and password."); return; }
      const nameFromEmail = form.email.split("@")[0].replace(/[._\d]/g, " ").trim().replace(/\b\w/g, c => c.toUpperCase());
      setLoading(true);
      await onLogin("student", { name: form.name || nameFromEmail, email: form.email, college: form.college || deriveCollegeFromEmail(form.email), _isSignup: false }, form.password);
      setLoading(false);
      return;
    }
    // Signup
    if (!form.name || !form.email || !form.password) { setLocalError("Please fill all required fields."); return; }
    if (!form.email.includes("@") || (!form.email.includes(".edu") && !form.email.includes("ac.in"))) {
      setLocalError("Please use your college email address."); return;
    }
    if (form.password !== form.confirm) { setLocalError("Passwords don't match."); return; }
    setLoading(true);
    await onLogin("student", { name: form.name.trim(), email: form.email.trim(), college: form.college || deriveCollegeFromEmail(form.email), _isSignup: true }, form.password);
    setLoading(false);
  };

  return (
    <div style={{ minHeight: "100vh", background: `linear-gradient(135deg,#e8f4fd,#e8faf5)`, display: "flex", alignItems: "center", justifyContent: "center", padding: 20, fontFamily: "'Segoe UI',system-ui,sans-serif" }}>
      <div style={{ width: "100%", maxWidth: 480 }}>
        <div style={{ textAlign: "center", marginBottom: 24 }}>
          <img src={CAMPUS_TRIAGE_LOGO} alt="CampusTriage" style={{ height: 56, width: "auto", objectFit: "contain", display: "block", margin: "0 auto" }} />
          <div style={{ fontSize: 13, color: COLORS.textSecondary, marginTop: 4 }}>
            {isDocSignup ? "Doctor Registration" : isDoc ? "Doctor Portal" : isLogin ? "Student Login" : "Student Registration"}
          </div>
        </div>
        <Card>
          {!isDocSignup ? (
            <>
              {!isDoc && !isLogin && <Input label="Full Name" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="Your full name" required />}
              <Input label="Email Address" type="email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} placeholder={isDoc ? "doctor@hospital.com" : "you@college.ac.in"} required />
              {!isDoc && !isLogin && <Input label="College / University" value={form.college} onChange={e => setForm({ ...form, college: e.target.value })} placeholder="e.g. BITS Pilani, Hyderabad" />}
              <Input label="Password" type="password" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} placeholder="••••••••" required />
              {!isDoc && !isLogin && <Input label="Confirm Password" type="password" value={form.confirm} onChange={e => setForm({ ...form, confirm: e.target.value })} placeholder="••••••••" required />}
            </>
          ) : (
            <>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 0 }}>
                <div style={{ paddingRight: 8 }}><Input label="Full Name" value={docForm.name} onChange={e => setDocForm({ ...docForm, name: e.target.value })} placeholder="Dr. Full Name" required /></div>
                <div style={{ paddingLeft: 8 }}><Input label="Email" type="email" value={docForm.email} onChange={e => setDocForm({ ...docForm, email: e.target.value })} placeholder="doctor@email.com" required /></div>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 0 }}>
                <div style={{ paddingRight: 8 }}><Input label="Password" type="password" value={docForm.password} onChange={e => setDocForm({ ...docForm, password: e.target.value })} placeholder="••••••••" /></div>
                <div style={{ paddingLeft: 8 }}><Input label="Phone" value={docForm.phone} onChange={e => setDocForm({ ...docForm, phone: e.target.value })} placeholder="+91 98765 43210" /></div>
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 0 }}>
                <div style={{ paddingRight: 8 }}><Input label="Gender" options={["Male", "Female", "Other"]} value={docForm.gender} onChange={e => setDocForm({ ...docForm, gender: e.target.value })} /></div>
                <div style={{ paddingLeft: 8 }}><Input label="Experience (yrs)" value={docForm.experience} onChange={e => setDocForm({ ...docForm, experience: e.target.value })} placeholder="e.g. 8" /></div>
              </div>
              <Input label="Qualification" value={docForm.qualification} onChange={e => setDocForm({ ...docForm, qualification: e.target.value })} placeholder="MBBS, MD, etc." />
              <Input label="Hospital / Clinic" value={docForm.hospital} onChange={e => setDocForm({ ...docForm, hospital: e.target.value })} placeholder="Hospital or clinic name" />
              <Input label="Specialization" options={specializations} value={docForm.specialization} onChange={e => setDocForm({ ...docForm, specialization: e.target.value })} />
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 0 }}>
                <div style={{ paddingRight: 8 }}><Input label="Consultation Fee (₹)" value={docForm.fee} onChange={e => setDocForm({ ...docForm, fee: e.target.value })} placeholder="300" /></div>
                <div style={{ paddingLeft: 8 }}><Input label="Available Timings" value={docForm.timings} onChange={e => setDocForm({ ...docForm, timings: e.target.value })} placeholder="9am–5pm" /></div>
              </div>
              <Input label="Medical License ID" value={docForm.licenseId} onChange={e => setDocForm({ ...docForm, licenseId: e.target.value })} placeholder="MCI-XXXXX" required />
            </>
          )}
          {error && <div style={{ background: "#fee2e2", color: "#991b1b", borderRadius: 8, padding: "8px 12px", fontSize: 13, marginBottom: 12 }}>{error}</div>}
          <Btn variant="primary" onClick={handle} style={{ width: "100%", padding: "12px", fontSize: 15, borderRadius: 10, marginTop: 4, opacity: loading ? 0.7 : 1 }}>
            {loading ? "⏳ Please wait…" : isDocSignup ? "Create Doctor Account" : isDoc ? "Login to Doctor Portal" : isLogin ? "Login" : "Create Student Account"}
          </Btn>
          <div style={{ textAlign: "center", marginTop: 16, fontSize: 13, color: COLORS.textSecondary }}>
            {isDoc ? (
              <><span style={{ cursor: "pointer", color: COLORS.primary }} onClick={() => onNav(isDocSignup ? "doctorLogin" : "doctorSignup")}>{isDocSignup ? "Already have an account? Login" : "New doctor? Register here"}</span></>
            ) : (
              <><span style={{ cursor: "pointer", color: COLORS.primary }} onClick={() => onNav(isLogin ? "studentSignup" : "studentLogin")}>{isLogin ? "New student? Sign up" : "Already have an account? Login"}</span></>
            )}
          </div>
          <div style={{ textAlign: "center", marginTop: 8 }}>
            <span style={{ cursor: "pointer", fontSize: 12, color: COLORS.textSecondary }} onClick={() => onNav("landing")}>← Back to Home</span>
          </div>
        </Card>
      </div>
    </div>
  );
}

